import React, { useState, useEffect, useRef } from "react";
import "../styles/GeneralChat.css";

const greetings = ["hi", "hello", "hey", "hai"];

const emotionReplies = {
  happy: "That’s lovely to hear 💛 What’s been making you feel this way?",
  sad: "I’m really sorry you’re feeling this way 💙 Do you want to talk about it?",
  angry: "It sounds frustrating 😔 What happened?",
  anxious: "That sounds stressful 💭 I’m here with you.",
  neutral:
    "Thank you for sharing 💜 It’s completely okay to feel this way. Would you like to talk more about it?"
};

const detectEmotion = (text) => {
  const t = text.toLowerCase();

  if (t.includes("happy") || t.includes("good")) return "happy";
  if (t.includes("sad") || t.includes("down")) return "sad";
  if (t.includes("angry") || t.includes("mad")) return "angry";
  if (t.includes("anxious") || t.includes("worried")) return "anxious";

  return "neutral";
};

export default function GeneralChat() {
  const [messages, setMessages] = useState([]);
  const [input, setInput] = useState("");
  const [emotionStarted, setEmotionStarted] = useState(false);
  const chatEndRef = useRef(null);

  useEffect(() => {
    setMessages([
      {
        sender: "bot",
        text: "Hello 👋 I’m really glad you’re here."
      }
    ]);
  }, []);

  useEffect(() => {
    chatEndRef.current?.scrollIntoView({ behavior: "smooth" });
  }, [messages]);

  const handleSend = () => {
    if (!input.trim()) return;

    const userText = input.trim();
    setMessages((prev) => [...prev, { sender: "user", text: userText }]);
    setInput("");

    const lower = userText.toLowerCase();

    // ✅ STEP 1: Greeting only
    if (!emotionStarted && greetings.includes(lower)) {
      setTimeout(() => {
        setMessages((prev) => [
          ...prev,
          {
            sender: "bot",
            text: "Hi 😊 How are you feeling today?"
          }
        ]);
      }, 600);
      return;
    }

    // ✅ STEP 2: First emotion explanation
    if (!emotionStarted) {
      setEmotionStarted(true);
      const emotion = detectEmotion(userText);

      setTimeout(() => {
        setMessages((prev) => [
          ...prev,
          {
            sender: "bot",
            text: emotionReplies[emotion]
          }
        ]);
      }, 700);
      return;
    }

    // ✅ STEP 3: Normal conversation
    setTimeout(() => {
      setMessages((prev) => [
        ...prev,
        {
          sender: "bot",
          text: "I’m listening 💙 Tell me more."
        }
      ]);
    }, 700);
  };

  return (
    <div className="chat-container">
      <div className="chat-header">General Chat</div>

      <div className="chat-body">
        {messages.map((msg, i) => (
          <div key={i} className={`chat-message ${msg.sender}`}>
            {msg.text}
          </div>
        ))}
        <div ref={chatEndRef} />
      </div>

      <div className="chat-input">
        <input
          type="text"
          placeholder="Type how you feel..."
          value={input}
          onChange={(e) => setInput(e.target.value)}
          onKeyDown={(e) => e.key === "Enter" && handleSend()}
        />
        <button onClick={handleSend}>Send</button>
      </div>
    </div>
  );
}
